import { NextResponse, type NextRequest } from "next/server";
import { ADMIN_COOKIE_NAME } from "@/lib/auth";

/**
 * Middleware protecting /admin/* routes.
 * Exempts /admin/login (the login page) and /api/admin/login (the login API).
 * Runs on Edge runtime — only simple cookie string comparison.
 */
export function middleware(request: NextRequest) {
  const { pathname } = request.nextUrl;

  // Allow access to the login page and login API without authentication
  if (pathname === "/admin/login" || pathname === "/api/admin/login") {
    return NextResponse.next();
  }

  // Check for admin cookie
  const adminCookie = request.cookies.get(ADMIN_COOKIE_NAME);
  if (adminCookie?.value === "authenticated") {
    return NextResponse.next();
  }

  // Redirect unauthenticated users to /admin/login
  const loginUrl = new URL("/admin/login", request.url);
  return NextResponse.redirect(loginUrl);
}

export const config = {
  matcher: ["/admin/:path*", "/api/admin/:path*"],
};

// This is your Prisma schema file,
// learn more about it in the docs: https://pris.ly/d/prisma-schema

generator client {
  provider = "prisma-client"
  output   = "../generated/prisma"
}

datasource db {
  provider = "sqlite"
}

// ─── Enums ──────────────────────────────────────────────────────────

enum Category {
  DRINK
  FOOD
}

enum OrderStatus {
  PENDING
  CONFIRMED
  PREPARING
  READY
  SERVED
  PAID
  CANCELLED
}

enum ItemStatus {
  PENDING
  PREPARING
  READY
  SERVED
  CANCELLED
}

// ─── Models ─────────────────────────────────────────────────────────

model MenuItem {
  id          Int        @id @default(autoincrement())
  name        String
  category    Category
  price       Int        // VND — no decimals needed
  description String?
  available   Boolean    @default(true)
  sortOrder   Int        @default(0)
  createdAt   DateTime   @default(now())
  orderItems  OrderItem[]

  @@map("menu_items")
}

model Table {
  id     Int     @id @default(autoincrement())
  number Int     @unique
  name   String  // e.g. "Bàn 1"
  orders Order[]

  @@map("tables")
}

model Order {
  id          Int         @id @default(autoincrement())
  tableId     Int
  table       Table       @relation(fields: [tableId], references: [id])
  status      OrderStatus @default(PENDING)
  totalAmount Int         @default(0)
  paidAt      DateTime?
  createdAt   DateTime    @default(now())
  items       OrderItem[]

  @@map("orders")
}

model OrderItem {
  id         Int        @id @default(autoincrement())
  orderId    Int
  order      Order      @relation(fields: [orderId], references: [id])
  menuItemId Int
  menuItem   MenuItem   @relation(fields: [menuItemId], references: [id])
  quantity   Int        @default(1)
  status     ItemStatus @default(PENDING)
  notes      String?
  createdAt  DateTime   @default(now())

  @@map("order_items")
}

import { NextResponse } from 'next/server'
import { prisma } from '@/lib/prisma'

/**
 * GET /api/staff/menu
 *
 * Returns all menu items sorted by sortOrder ascending.
 * Used by the add-item modal to display available menu items.
 *
 * Returns: { items: MenuItem[] }
 */
export async function GET() {
  try {
    const menuItems = await prisma.menuItem.findMany({
      orderBy: { sortOrder: 'asc' },
      select: {
        id: true,
        name: true,
        price: true,
        category: true,
        available: true,
        sortOrder: true,
      },
    })

    console.log(
      `[GET /api/staff/menu] Returning ${menuItems.length} menu items`
    )

    return NextResponse.json({ items: menuItems })
  } catch (error) {
    console.error('[GET /api/staff/menu] Failed to fetch menu items:', error)
    return NextResponse.json(
      { error: 'Không thể tải danh sách món. Vui lòng thử lại.' },
      { status: 500 }
    )
  }
}

import { NextRequest, NextResponse } from 'next/server'
import { prisma } from '@/lib/prisma'
import { broadcast } from '@/lib/sse'

type OrderItemInput = {
  menuItemId: number
  quantity: number
  notes?: string
}

type OrderRequestBody = {
  tableId: number
  items: OrderItemInput[]
}

export async function POST(request: NextRequest) {
  // ─── Parse body ───────────────────────────────────────────────────
  let body: OrderRequestBody
  try {
    body = await request.json()
  } catch {
    return NextResponse.json(
      { error: 'Dữ liệu không hợp lệ.' },
      { status: 400 },
    )
  }

  const { tableId, items } = body

  // ─── Validate shape ───────────────────────────────────────────────
  if (
    typeof tableId !== 'number' ||
    !Array.isArray(items) ||
    items.length === 0
  ) {
    return NextResponse.json(
      { error: 'Dữ liệu đơn hàng không hợp lệ.' },
      { status: 400 },
    )
  }

  // ─── Validate quantities ──────────────────────────────────────────
  for (const item of items) {
    if (
      typeof item.menuItemId !== 'number' ||
      typeof item.quantity !== 'number' ||
      !Number.isInteger(item.quantity) ||
      item.quantity <= 0
    ) {
      return NextResponse.json(
        { error: 'Số lượng phải là số nguyên dương.' },
        { status: 400 },
      )
    }
  }

  // ─── Validate table exists ────────────────────────────────────────
  const table = await prisma.table.findUnique({ where: { id: tableId } })
  if (!table) {
    return NextResponse.json(
      { error: 'Bàn không tồn tại.' },
      { status: 404 },
    )
  }

  // ─── Validate menu items exist and are available ──────────────────
  const menuItemIds = items.map((i) => i.menuItemId)
  const menuItems = await prisma.menuItem.findMany({
    where: { id: { in: menuItemIds } },
  })

  const menuItemMap = new Map(menuItems.map((mi) => [mi.id, mi]))

  // Check for missing items
  const missingIds = menuItemIds.filter((id) => !menuItemMap.has(id))
  if (missingIds.length > 0) {
    return NextResponse.json(
      { error: 'Một số món không tồn tại.', missingItems: missingIds },
      { status: 400 },
    )
  }

  // Check for unavailable items
  const unavailableItems = items
    .filter((i) => {
      const mi = menuItemMap.get(i.menuItemId)
      return mi && !mi.available
    })
    .map((i) => i.menuItemId)

  if (unavailableItems.length > 0) {
    return NextResponse.json(
      { error: 'Một số món đã hết hàng', unavailableItems },
      { status: 409 },
    )
  }

  // ─── Compute totalAmount server-side ──────────────────────────────
  const totalAmount = items.reduce((sum, item) => {
    const menuItem = menuItemMap.get(item.menuItemId)!
    return sum + menuItem.price * item.quantity
  }, 0)

  // ─── Create Order + OrderItems in transaction ─────────────────────
  try {
    const order = await prisma.$transaction(async (tx) => {
      const newOrder = await tx.order.create({
        data: {
          tableId,
          totalAmount,
          status: 'PENDING',
        },
      })

      await tx.orderItem.createMany({
        data: items.map((i) => ({
          orderId: newOrder.id,
          menuItemId: i.menuItemId,
          quantity: i.quantity,
          notes: i.notes || null,
          status: 'PENDING',
        })),
      })

      // Re-fetch with items + menuItem names + table info for response & broadcast
      return tx.order.findUniqueOrThrow({
        where: { id: newOrder.id },
        include: {
          table: true,
          items: {
            include: {
              menuItem: { select: { id: true, name: true, category: true, price: true } },
            },
          },
        },
      })
    })

    // Broadcast new order to all SSE subscribers (no station filter —
    // both bar and kitchen may have relevant items)
    console.log(`[POST /api/order] Broadcasting new-order event for order #${order.id}`)
    broadcast('new-order', order)

    return NextResponse.json({ order }, { status: 201 })
  } catch (error) {
    console.error('[POST /api/order] Transaction failed:', error)
    return NextResponse.json(
      { error: 'Không thể tạo đơn hàng. Vui lòng thử lại.' },
      { status: 500 },
    )
  }
}

import { prisma } from '@/lib/prisma'
import ErrorPage from '@/components/order/ErrorPage'
import MenuView from '@/components/order/MenuView'
import CartUI from '@/components/order/CartUI'
import { CartProvider } from '@/components/order/CartProvider'

const INVALID_TABLE_MSG =
  'Bàn không hợp lệ. Vui lòng scan lại mã QR tại bàn của bạn.'

export default async function OrderPage({
  searchParams,
}: {
  searchParams: Promise<{ [key: string]: string | string[] | undefined }>
}) {
  const { table } = await searchParams

  // --- Table validation ---
  const tableStr = typeof table === 'string' ? table : undefined
  const tableNum = tableStr ? parseInt(tableStr, 10) : NaN

  if (!tableStr || isNaN(tableNum)) {
    return <ErrorPage message={INVALID_TABLE_MSG} />
  }

  const tableRecord = await prisma.table.findFirst({
    where: { number: tableNum },
  })

  if (!tableRecord) {
    return <ErrorPage message={INVALID_TABLE_MSG} />
  }

  // --- Fetch all menu items sorted by sortOrder ---
  const menuItems = await prisma.menuItem.findMany({
    orderBy: { sortOrder: 'asc' },
  })

  // Serialize to plain objects for client component boundary
  const items = menuItems.map((item) => ({
    id: item.id,
    name: item.name,
    category: item.category as 'DRINK' | 'FOOD',
    price: item.price,
    description: item.description,
    available: item.available,
    sortOrder: item.sortOrder,
  }))

  const tableInfo = {
    id: tableRecord.id,
    number: tableRecord.number,
    name: tableRecord.name,
  }

  return (
    <div className="min-h-dvh bg-amber-50">
      <CartProvider tableId={tableInfo.id}>
        <CartUI tableId={tableInfo.id} tableNumber={tableInfo.number}>
          <MenuView menuItems={items} table={tableInfo} />
        </CartUI>
      </CartProvider>
    </div>
  )
}

