const hasHidden = schema.includes('hidden');
console.log(`\n=== Schema hidden field: ${hasHidden ? '✅ present' : '❌ MISSING'} ===`);

// Check migration directories  
const migrDir = path.join(base, 'prisma/migrations');
if (fs.existsSync(migrDir)) {
